import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"게임 실행하기","description":"실제 게임 환경에서 모드를 디버깅하기 위해 다양한 실행 프로필을 활용하는 방법에 대해 알아보세요.","frontmatter":{"title":"게임 실행하기","description":"실제 게임 환경에서 모드를 디버깅하기 위해 다양한 실행 프로필을 활용하는 방법에 대해 알아보세요.","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.10/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.10/translated/ko_kr/develop/getting-started/launching-the-game.md","lastUpdated":1766682904000}`);var c={name:`ko_kr/1.21.10/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">게임 실행하기 <a class="header-anchor" href="#h1" aria-label="Permalink to “게임 실행하기”">​</a></h1><p>Fabric Loom은 실제 게임 환경에서 모드를 디버깅할 수 있게 돕는 다양한 실행 프로필을 제공합니다. 이 설명서는 모드를 디버깅하고 테스트하기 위해 다양한 실행 프로필을 활용하는 방법에 대해 알아봅니다.</p><h2 id="launch-profiles" tabindex="-1">실행 프로필 <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “실행 프로필”">​</a></h2><p>IntelliJ IDEA를 사용하고 있다면, 창의 우측 상단 모서리에서 실행 프로필을 찾을 수 있습니다. 드롭다운 메뉴를 클릭하여 사용 가능한 실행 프로필을 확인할 수 있습니다.</p><p>다음과 같이 단순 실행과 디버그 모드로 실행 가능한 클라이언트와 서버 프로필이 있어야 합니다:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="실행 프로필" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Gradle 작업 <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Gradle 작업”">​</a></h2><p>명령줄을 사용한다면, 다음 Gradle 작업으로 게임을 실행할 수 있습니다:</p><ul><li><code>./gradlew runClient</code> - 클라이언트 모드로 게임을 시작합니다.</li><li><code>./gradlew runServer</code> - 서버 모드로 게임을 시작합니다.</li></ul><p>이 방식의 유일한 문제는 코드를 쉽게 디버깅할 수 없다는 것입니다. 코드를 디버깅하려면, IntelliJ IDEA 등 IDE에서 제공하는 Gradle 통합의 실행 프로필을 사용해야 합니다.</p><h2 id="hotswapping-classes" tabindex="-1">클래스 핫스왑 <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “클래스 핫스왑”">​</a></h2><p>게임을 디버그 모드로 실행하면, 게임을 재시작하지 않고도 클래스를 핫스왑(수정)할 수 있습니다. 이는 코드의 변경 사항을 빠르게 테스트할 때 유용합니다.</p><p>하지만 몇 가지 제한 사항이 존재합니다:</p><ul><li>메소드를 추가하거나 제거할 수 없습니다</li><li>메소드의 매개변수를 수정할 수 없습니다</li><li>필드를 추가하거나 제거할 수 없습니다</li></ul><p>하지만, <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains 런타임</a>을 사용하면 대부분의 제한 사항을 우회할 수 있으며, 심지어 클래스와 메소드를 추가하거나 제거할 수도 있습니다. 이는 게임을 재시작하지 않고도 대부분의 변경 사항을 적용할 수 있게 <em>해야</em> 합니다.</p><p>Minecraft 실행 구성에 다음 VM 변수를 추가하는 것을 잊지 마세요:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Mixin 핫스왑 <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Mixin 핫스왑”">​</a></h2><p>Mixin을 사용한다면, 아래 과정을 통해 게임을 재시작하지 않고 Mixin 클래스를 핫스왑할 수 있습니다. 이는 Mixin 변경 사항을 빠르게 테스트하기 유용합니다.</p><p>이를 위해선 먼저 Mixin Java 에이전트를 설치해야 합니다.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Mixin 라이브러리 Jar 위치 지정 <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Mixin 라이브러리 Jar 위치 지정”">​</a></h3><p>IntelliJ IDEA를 사용중이라면, 다음과 같이 &quot;프로젝트 구조&quot;의 &quot;외부 라이브러리&quot;에서 Mixin 라이브러리 Jar를 찾을 수 있습니다:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin 라이브러리" loading="lazy"></p><p>다음 과정을 위해 Jar의 &quot;상대 경로&quot;를 복사해야 합니다.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. <code>-javaagent</code> VM 변수 추가 <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. -javaagent VM 변수 추가”">​</a></h3><p>&quot;Minecraft Client&quot;와 &quot;Minecraft Server&quot; 실행 구성에서, 다음 VM 매개변수를 추가해야 합니다:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;&lt;여기에 Mixin 라이브러리 Jar 상대 경로 입력&gt;&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="VM 매개변수가 강조된 실행 구성" loading="lazy"></p><p>이제, 디버깅 중에 Mixin 메소드를 수정할 수 있으며, 게임을 재시작하지 않고 변경 사항을 확인할 수 있습니다.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};